-- RC1.4.3 versioned Client Portal onboarding.
CREATE TABLE IF NOT EXISTS client_onboarding_states (id SERIAL PRIMARY KEY, client_user_id INTEGER NOT NULL REFERENCES client_users(id) ON DELETE CASCADE, onboarding_version VARCHAR(30) NOT NULL, status VARCHAR(20) NOT NULL DEFAULT 'not_started', current_step INTEGER NOT NULL DEFAULT 0, started_at TIMESTAMP, completed_at TIMESTAMP, skipped_at TIMESTAMP, last_replay_at TIMESTAMP, replay_active BOOLEAN NOT NULL DEFAULT FALSE, updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT uq_client_onboarding_user_version UNIQUE (client_user_id,onboarding_version), CONSTRAINT ck_client_onboarding_status CHECK (status IN ('not_started','in_progress','completed','skipped')), CONSTRAINT ck_client_onboarding_step CHECK (current_step BETWEEN 0 AND 7));
CREATE INDEX IF NOT EXISTS ix_client_onboarding_states_user ON client_onboarding_states(client_user_id);
CREATE INDEX IF NOT EXISTS ix_client_onboarding_status ON client_onboarding_states(onboarding_version,status);
-- Upgrade backfill: current users are existing; users created later have no row and receive onboarding.
INSERT INTO client_onboarding_states (client_user_id,onboarding_version,status,current_step,skipped_at,replay_active,updated_at) SELECT id,'rc1.4.3','skipped',0,CURRENT_TIMESTAMP,FALSE,CURRENT_TIMESTAMP FROM client_users ON CONFLICT (client_user_id,onboarding_version) DO NOTHING;
